 {"id":"frankenredis-d54f","title":"Fix UNLINK wrong-arity parity and restore live core_server case","description":"UNLINK currently routes through the shared DEL implementation and reports DEL in wrong-arity errors. Make UNLINK report its own command name, restore unlink_wrong_arity to the stable core_server live Redis subset, and verify with targeted rch conformance checks.","status":"closed","priority":2,"issue_type":"task","created_at":"2026-04-18T23:09:14.387605988Z","created_by":"ubuntu","updated_at":"2026-04-18T23:22:51.583258054Z","closed_at":"2026-04-18T23:22:51.581332178Z","close_reason":"Completed","source_repo":".","compaction_level":0,"original_size":0}
 {"id":"frankenredis-ddl1","title":"Reject CONFIG SET unixsocketperm as immutable","description":"Redis marks unixsocketperm as IMMUTABLE_CONFIG in legacy_redis_code/redis/src/config.c. FrankenRedis exposes unixsocketperm as a static CONFIG parameter and currently accepts CONFIG SET through the static fallback. Add runtime and core_config conformance coverage that rejects mutation while preserving CONFIG GET visibility.","status":"closed","priority":1,"issue_type":"task","created_at":"2026-04-18T12:13:34.853226355Z","created_by":"ubuntu","updated_at":"2026-04-18T12:24:46.399963863Z","closed_at":"2026-04-18T12:24:46.397655583Z","close_reason":"Completed","source_repo":".","compaction_level":0,"original_size":0,"labels":["config","conformance","upstream-parity"]}

